282	
283	export function stopStatusServer(): void {
284	  httpServer?.close();
285	  httpServer = undefined;
286	}
287	
288	// ─── SSE broadcast ─────────────────────────────────────────────────────────
289	
290	/** Broadcast an SSE event to all clients watching a task. */
291	export function broadcastSSE(taskId: string, data: Record<string, unknown>): void {
292	  const clients = sseClients.get(taskId);
293	  if (!clients || clients.size === 0) return;
294	  const payload = `data: ${JSON.stringify(data)}\n\n`;
295	  for (const res of clients) {
296	    res.write(payload);
297	  }
298	}
299	
300	function sseSend(res: ServerResponse, data: Record<string, unknown>): void {
301	  res.write(`data: ${JSON.stringify(data)}\n\n`);
302	}
303	
304	function json(res: ServerResponse, data: unknown, status = 200): void {
305	  res.writeHead(status, { "Content-Type": "application/json" });
306	  res.end(JSON.stringify(data));
307	}
